import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [user, setUser] = useState(null);
  const [students, setStudents] = useState([]);
  const [view, setView] = useState("dashboard");
  const [id, setId] = useState("");
  const [pass, setPass] = useState("");

  useEffect(() => {
    if (user?.role === 'admin') axios.get('http://localhost:3000/admin/students').then(res => setStudents(res.data));
  }, [user]);

  const updateData = (sid, field, value) => {
    axios.put(`http://localhost:3000/admin/update/${encodeURIComponent(sid)}`, { [field]: value });
  };

  const calcAttendance = (s) => {
    const total = s.joogay + s.maqnaa;
    return total === 0 ? 100 : Math.round((s.joogay / total) * 100);
  };

  if (!user) {
    return (
      <div style={loginBox}>
        <h2 style={{color: '#1a73e8'}}>UOB Student Portal 2026</h2>
        <input placeholder="ID (Tusaale: BCS/S18430/2026)" onChange={e => setId(e.target.value)} style={inputS} />
        <input type="password" placeholder="Password" onChange={e => setPass(e.target.value)} style={inputS} />
        <button onClick={() => {
          axios.post('http://localhost:3000/login', { id, password: pass })
          .then(res => setUser(res.data)).catch(() => alert("Password ama ID waa khalad!"));
        }} style={btnMain}>Geli Account-ka</button>
      </div>
    );
  }

  return (
    <div style={{ display: 'flex', height: '100vh', fontFamily: 'Arial' }}>
      {/* SIDEBAR - MENU IS HOOS YAAL */}
      <div style={sidebar}>
        <h3 style={{borderBottom: '1px solid #555', paddingBottom: '10px'}}>UOB MENU</h3>
        <button onClick={() => setView("dashboard")} style={view === "dashboard" ? activeBtn : menuBtn}>🏠 Dashboard</button>
        <button onClick={() => setView("exam")} style={view === "exam" ? activeBtn : menuBtn}>📝 Exam Results</button>
        <button onClick={() => setView("xadiris")} style={view === "xadiris" ? activeBtn : menuBtn}>📅 Attendance (100%)</button>
        <button onClick={() => setView("lacagta")} style={view === "lacagta" ? activeBtn : menuBtn}>💰 Fees Status</button>
        <button onClick={() => setUser(null)} style={logoutBtn}>Logout</button>
      </div>

      {/* CONTENT AREA */}
      <div style={{ flex: 1, padding: '25px', background: '#f8f9fa', overflowY: 'auto' }}>
        {user.role === 'admin' ? (
          <div>
            <h2>Maamulka Sannadka 2026</h2>
            <table border="1" width="100%" style={tableS}>
              <thead style={{background: '#2c3e50', color: 'white'}}>
                <tr><th>ID (Kursiga)</th><th>Magaca</th>
                {view === "exam" ? <th>Maadooyinka</th> : view === "xadiris" ? <th>Xadiris (√/X)</th> : <th>Lacagta</th>}
                <th>Natiijada %</th></tr>
              </thead>
              <tbody>
                {students.map(s => (
                  <tr key={s.id} style={{textAlign: 'center'}}>
                    <td style={{padding: '10px'}}>{s.id}</td><td>{s.magaca}</td>
                    <td>
                      {view === "exam" ? s.exam.map((m, i) => (
                        <input key={i} type="number" defaultValue={m} style={{width: '35px'}} 
                        onBlur={e => { let n = [...s.exam]; n[i] = e.target.value; updateData(s.id, 'exam', n); }} />
                      )) : view === "xadiris" ? (
                        <>
                          <button onClick={() => updateData(s.id, 'joogay', s.joogay + 1)} style={tick}>√ Sax</button>
                          <button onClick={() => updateData(s.id, 'maqnaa', s.maqnaa + 1)} style={cross}>X Maqan</button>
                        </>
                      ) : (
                        <select defaultValue={s.lacagta} onChange={e => updateData(s.id, 'lacagta', e.target.value)}>
                          <option value="Bixiyey">Bixiyey</option><option value="Ma bixin">Ma bixin</option>
                        </select>
                      )}
                    </td>
                    <td style={{fontWeight: 'bold'}}>{view === "xadiris" ? calcAttendance(s) + "%" : "Ready"}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div style={{textAlign: 'center', marginTop: '50px'}}>
             <h1>UOB Portal 2026</h1>
             <div style={card}>
                <h2>ID-gaaga: {user.id}</h2>
                <hr/>
                <h3>Xadiriska: {calcAttendance(user)}%</h3>
                <p>Status-ka Lacagta: {user.lacagta}</p>
                <p style={{fontSize: '12px', color: '#888'}}>* Xogtan waxaa soo saaray nidaamka 2026</p>
             </div>
          </div>
        )}
      </div>
    </div>
  );
}

// STYLES
const loginBox = { display: 'flex', flexDirection: 'column', alignItems: 'center', marginTop: '120px' };
const inputS = { padding: '15px', margin: '8px', width: '320px', borderRadius: '8px', border: '1px solid #ccc' };
const btnMain = { padding: '15px 50px', background: '#1a73e8', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' };
const sidebar = { width: '240px', background: '#1c2833', color: 'white', padding: '20px', display: 'flex', flexDirection: 'column', gap: '10px' };
const menuBtn = { padding: '15px', cursor: 'pointer', textAlign: 'left', border: 'none', background: 'transparent', color: '#abb2b9', borderRadius: '5px' };
const activeBtn = { ...menuBtn, background: '#1a73e8', color: 'white' };
const logoutBtn = { ...menuBtn, background: '#c0392b', color: 'white', marginTop: 'auto' };
const tableS = { borderCollapse: 'collapse', background: 'white', marginTop: '20px', boxShadow: '0 2px 5px rgba(0,0,0,0.1)' };
const tick = { background: '#27ae60', color: 'white', border: 'none', padding: '5px 10px', cursor: 'pointer', marginRight: '5px' };
const cross = { background: '#e74c3c', color: 'white', border: 'none', padding: '5px 10px', cursor: 'pointer' };
const card = { background: 'white', padding: '40px', borderRadius: '20px', display: 'inline-block', boxShadow: '0 10px 20px rgba(0,0,0,0.1)' };

export default App;
